{
  "grammar": [
    {
      "pattern": "坐 + transportation + 去 + place",
      "structure": ["verb", "transportation", "verb", "place"],
      "explanation_en": "Use '坐' (to ride/take) followed by a vehicle, then '去' (to go) and a destination to express going somewhere by a specific mode of transport.",
      "title": "Going by Transport: 坐...去...",
      "meaning": "Take [transport] to go to [place]",
      "when_to_use": ["When stating how you travel to a destination", "When giving directions involving public transport", "When describing your commute or travel plans"],
      "when_not_to_use": ["Do not use for walking (use 走路 instead)", "Do not use for actions that don't involve movement (e.g., sitting in a chair)"],
      "pragmatic_notes": "In Taiwan, 坐 is used for all vehicles (bus, MRT, taxi, bike). For taxi, you can also say 叫計程車 (call a taxi) instead of 坐計程車.",
      "word_order_notes": "The structure is fixed: 坐 + vehicle + 去 + place. The vehicle must come before the destination.",
      "english_contrast": "English says 'take the bus to school' (verb + vehicle + to + place). Chinese uses two verbs: 坐 (take) and 去 (go).",
      "korean_contrast": "Korean uses '-(으)로 가다' (e.g., 버스로 가다). Chinese uses a separate verb 坐 for the vehicle, while Korean attaches the vehicle as a means marker.",
      "negative_examples": [
        {
          "text": "我去坐公車學校。",
          "error": "Wrong word order: 去 should come after 坐公車, not before. Correct: 坐公車去學校。"
        },
        {
          "text": "我坐去學校公車。",
          "error": "Vehicle must come before 去, not after. Correct: 坐公車去學校。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我坐公車去學校。",
          "error": "This is actually correct! Use it as a model."
        },
        {
          "text": "我坐捷運去台北車站。",
          "error": "Correct example: 坐捷運去台北車站 means 'take the MRT to Taipei Main Station'."
        }
      ],
      "transformation_drills": ["Change '我坐公車去學校' to use 捷運 instead of 公車.", "Change '我坐計程車去醫院' to use 火車 instead of 計程車."],
      "production_drills": ["Say you take the MRT to the park.", "Say you take a taxi to the restaurant."],
      "common_error_patterns": ["Placing 去 before the vehicle", "Omitting 坐 and using only 去"],
      "repair_feedback": {
        "word_order": "Remember: 坐 + vehicle + 去 + place. The vehicle always comes before 去.",
        "politeness": "This structure is neutral and polite for everyday use.",
        "vocabulary": "Use 坐 for all vehicles. For taxi, 叫計程車 is also common."
      }
    },
    {
      "pattern": "從 + place A + 到 + place B + 怎麼去？",
      "structure": ["preposition", "place A", "preposition", "place B", "question word", "verb"],
      "explanation_en": "Use '從...到...怎麼去？' to ask how to get from one place to another. 怎麼 means 'how', and 去 means 'go'.",
      "title": "Asking How to Get There: 從...到...怎麼去？",
      "meaning": "How to go from [place A] to [place B]?",
      "when_to_use": ["When asking for directions between two locations", "When planning a route", "When inquiring about transportation options"],
      "when_not_to_use": ["Do not use for asking about a single location (use 怎麼去 + place instead)", "Do not use for asking about time (use 幾點 instead)"],
      "pragmatic_notes": "In Taiwan, you can also ask '怎麼去比較快？' (how to go faster) or '怎麼去比較便宜？' (how to go cheaper). This is very common at MRT stations or bus stops.",
      "word_order_notes": "The order is fixed: 從 + start place + 到 + end place + 怎麼去. The question word 怎麼 comes before the verb 去.",
      "english_contrast": "English says 'How do I get from A to B?' with 'get' as the main verb. Chinese uses 去 (go) and places 怎麼 before it.",
      "korean_contrast": "Korean uses 'A에서 B까지 어떻게 가요?' (A-eseo B-kkaji eotteoke gayo?). Chinese uses 從...到... instead of particles, and 怎麼去 corresponds to 어떻게 가요.",
      "negative_examples": [
        {
          "text": "從學校到公園怎麼去？",
          "error": "This is correct! Use it as a model."
        },
        {
          "text": "怎麼去從學校到公園？",
          "error": "Wrong word order: 怎麼去 must come at the end, not the beginning. Correct: 從學校到公園怎麼去？"
        }
      ],
      "incorrect_examples": [
        {
          "text": "從家到公司怎麼去？",
          "error": "Correct example: 從家到公司怎麼去？ means 'How to go from home to the company?'"
        },
        {
          "text": "從捷運站到圖書館怎麼去？",
          "error": "Correct example: 從捷運站到圖書館怎麼去？ means 'How to go from the MRT station to the library?'"
        }
      ],
      "transformation_drills": ["Change '從學校到公園怎麼去？' to use 醫院 instead of 公園.", "Change '從家到公司怎麼去？' to use 車站 instead of 公司."],
      "production_drills": ["Ask how to go from the MRT station to the school.", "Ask how to go from the hospital to the park."],
      "common_error_patterns": ["Placing 怎麼去 at the beginning", "Omitting 從 or 到"],
      "repair_feedback": {
        "word_order": "Always start with 從 + place A + 到 + place B, then end with 怎麼去.",
        "politeness": "This is a neutral question. For more politeness, add 請問 at the beginning.",
        "vocabulary": "Use 從 for 'from' and 到 for 'to'. 怎麼去 is the standard way to ask 'how to go'."
      }
    },
    {
      "pattern": "到 + place + 要 + time + 分鐘",
      "structure": ["verb", "place", "auxiliary verb", "time", "counter"],
      "explanation_en": "Use '到...要...分鐘' to express how many minutes it takes to reach a place. 要 means 'need/take', and 分鐘 means 'minutes'.",
      "title": "Time to Reach: 到...要...分鐘",
      "meaning": "It takes [time] minutes to get to [place]",
      "when_to_use": ["When stating travel duration", "When asking about how long a trip takes", "When planning schedules"],
      "when_not_to_use": ["Do not use for hours (use 小時 instead of 分鐘)", "Do not use for distances (use 公里 instead)"],
      "pragmatic_notes": "In Taiwan, people often say '大概要...分鐘' (approximately takes...minutes) for estimates. You can also ask '到...要多久？' (how long to get to...?).",
      "word_order_notes": "The structure is: 到 + place + 要 + number + 分鐘. The time expression comes after 要 and before 分鐘.",
      "english_contrast": "English says 'It takes 10 minutes to get to the station.' Chinese uses 到 (to reach) + place + 要 (need) + time + 分鐘.",
      "korean_contrast": "Korean uses '...까지 ...분 걸려요' (kkaji ...bun geollyeoyo). Chinese uses 到...要...分鐘, where 要 corresponds to 걸려요 (takes).",
      "negative_examples": [
        {
          "text": "到學校要十分鐘。",
          "error": "This is correct! Use it as a model."
        },
        {
          "text": "要十分鐘到學校。",
          "error": "Wrong word order: 到學校 must come before 要. Correct: 到學校要十分鐘。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "到公園要五分鐘。",
          "error": "Correct example: 到公園要五分鐘 means 'It takes 5 minutes to get to the park.'"
        },
        {
          "text": "到車站要二十分鐘。",
          "error": "Correct example: 到車站要二十分鐘 means 'It takes 20 minutes to get to the station.'"
        }
      ],
      "transformation_drills": ["Change '到學校要十分鐘' to use 十五分鐘 instead of 十分鐘.", "Change '到公園要五分鐘' to use 醫院 instead of 公園."],
      "production_drills": ["Say it takes 10 minutes to get to the MRT station.", "Say it takes 30 minutes to get to the company."],
      "common_error_patterns": ["Placing 要 before 到", "Omitting 分鐘 and using only the number"],
      "repair_feedback": {
        "word_order": "Remember: 到 + place + 要 + time + 分鐘. The place comes before 要.",
        "politeness": "This structure is neutral. For questions, add 嗎 at the end (e.g., 到學校要十分鐘嗎？).",
        "vocabulary": "Use 分鐘 for minutes. For hours, use 小時. For estimates, add 大概 before 要."
      }
    }
  ]
}
